 1	import * as React from 'react';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  FormSelect,
 6	  FormSelectOption,
 7	  HelperText,
 8	  HelperTextItem,
 9	} from '@patternfly/react-core';
10	import { useField, useFormikContext, FormikValues } from 'formik';
11	import { useFormikValidationFix } from '../pipelines-details/multi-column-field/formik-validation-fix';
12	import { getFieldId } from '../pipelines-details/multi-column-field/utils';
13	import { FieldProps } from '../pipelines-details/multi-column-field/types';
14	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
15	
16	export type FormSelectFieldOption<T = any> = {
17	  label: string;
18	  value: T;
19	  isPlaceholder?: boolean;
20	  isDisabled?: boolean;
21	};
22	
23	export type FormSelectFieldProps = FieldProps & {
24	  isDisabled?: boolean;
25	  options: FormSelectFieldOption[];
26	  onChange?: (selectedValue: any) => void;
27	};
28	
29	const FormSelectField: React.FC<FormSelectFieldProps> = ({
30	  label,
31	  helpText,
32	  required,
33	  options,
34	  ...props
35	}) => {
36	  const [field, { touched, error }] = useField(props.name);
37	  const { setFieldValue, setFieldTouched } = useFormikContext<FormikValues>();
38	  const fieldId = getFieldId(props.name, 'dropdown');
39	  const isValid = !(touched && error);
40	  const errorMessage = !isValid ? error : '';
41	
42	  useFormikValidationFix(field.value);
43	
44	  // PF bug workaround
45	  // Return to field.value when fixed: https://github.com/patternfly/patternfly-react/issues/5687
46	  const hasSelectedOption: boolean = options.some(
47	    ({ value }) => field.value === value,
48	  );
49	  const placeholderOption: FormSelectFieldOption = options.find(
50	    ({ isPlaceholder }) => isPlaceholder,
51	  );
52	  const safeValue: string = hasSelectedOption
53	    ? field.value
54	    : placeholderOption
55	    ? placeholderOption.value
56	    : field.value;
57	
58	  return (
59	    <FormGroup fieldId={fieldId} label={label} isRequired={required}>
60	      <FormSelect
61	        {...props}
62	        id={fieldId}
63	        aria-describedby={helpText ? `${fieldId}-helper` : undefined}
64	        onChange={(_event, value: any) => {
65	          props.onChange && props.onChange(value);
66	          // Validation is automatically done by the useFormikValidationFix above
67	          setFieldValue(props.name, value, false);
68	          setFieldTouched(props.name, true, false);
69	        }}
70	        value={safeValue}
71	      >
72	        {options.map((option) => (
73	          <FormSelectOption {...option} key={option.label} />
74	        ))}
75	      </FormSelect>
76	      <FormHelperText>
77	        <HelperText>
78	          {!isValid ? (
79	            <HelperTextItem variant="error" icon={<RedExclamationCircleIcon />}>
80	              {errorMessage}
81	            </HelperTextItem>
82	          ) : (
83	            <HelperTextItem>{helpText}</HelperTextItem>
84	          )}
85	        </HelperText>
86	      </FormHelperText>
87	    </FormGroup>
88	  );
89	};
90	
91	export default FormSelectField;

